  ('test_plan', '{"testLevels":[{"level":"Unit","scope":"engine math, parsing, validation helpers","tool":"pytest","status":"exists"},{"level":"Integration","scope":"route contract, DB, A→B→C cascade","tool":"pytest + TestClient","status":"exists"},{"level":"Data quality","scope":"census schema, edge cases, fallback ledger","tool":"pytest + edge datasets","status":"partial"},{"level":"E2E (user journey)","scope":"U1–U8 in a browser","tool":"Playwright","status":"gap"},{"level":"Smoke","scope":"upload→run→verdict on a running server","tool":"Playwright subset","status":"gap"},{"level":"Regression","scope":"golden fixture byte-identical","tool":"pytest golden","status":"exists"}],"userPath":[{"id":"U1","step":"Authenticate","where":"POST /api/login","note":"fail-closed — empty user table admits nobody"},{"id":"U2","step":"Upload census","where":"POST /api/preview","note":"verbatim preview, nothing normalized yet"},{"id":"U3","step":"Persist + review","where":"POST /api/census → CensusReview","note":"record in review status; flagged rows surfaced"},{"id":"U4","step":"Correct flagged rows","where":"POST /api/census/{id}/corrections","note":"each correction logged"},{"id":"U5","step":"Run the engines","where":"POST /api/census/{id}/run","note":"A→B→C cascade; status → final"},{"id":"U6","step":"Read the verdict","where":"GET /api/runs/{id}","note":"remediation (A+B) + healthcare pass/fail"},{"id":"U7","step":"Export","where":"run view → model","note":"structured paste into acquisition model"},{"id":"U8","step":"Share / manage","where":"POST /api/runs/{id}/shares","note":"owner-only share; ADMIN/ADVISOR roles"}],"testGroups":[{"stage":"Stage 0 — Upload & Normalization","cases":[{"id":"T-N1","assert":"Verbatim preview returns every original column unchanged","edges":["59-col template","newline headers"]},{"id":"T-N2","assert":"Parser maps aliases two-pass (exact→substring), order-sensitive","edges":["E1","E6"]},{"id":"T-N3","assert":"Every default/rejection lands in the fallback ledger — no silent drop","edges":["E3"]},{"id":"T-N4","assert":"Exempt status parsed correctly","edges":["E2"]},{"id":"T-N5","assert":"County resolved from ZIP; split-ZIP + home-office fallback","edges":["E9","E10","E11"]},{"id":"T-N6","assert":"Corrections persist + re-derive; review→final only after run","edges":["E7"]}]},{"stage":"Stage 1 — Fair Pay Engine A","cases":[{"id":"T-A1","assert":"Basket = MAX(MIT, EPI, ACS…); CNT transport is override not MAX","edges":["E12"]},{"id":"T-A2","assert":"Gross-up floored at max(0,…) — never negative","edges":["E13"]},{"id":"T-A3","assert":"Tax inputs derived from the same household as the basket","edges":["E14","E15"]},{"id":"T-A4","assert":"Local-tax states flagged (PolicyEngine is state-level)","edges":["E17"]},{"id":"T-A5","assert":"Only in-scope (non-exempt) employees counted","edges":["E2","E8"]}]},{"stage":"Stage 2 — PSL (B) + Healthcare (C), parallel","cases":[{"id":"T-B1","assert":"PSL floor per jurisdiction; preempted/no-cap → floor 0","edges":["E18","E19","E20"]},{"id":"T-B2","assert":"Non-exempt cost = hours-below × rate; PT prorated to 2080h","edges":["E21"]},{"id":"T-B3","assert":"B accumulates on A''s raised wages (cascade)","edges":["E13"]},{"id":"T-C1","assert":"Benchmarks 1/2A/2B per plan; verdict affordable/review/fail","edges":["E23","E24"]},{"id":"T-C2","assert":"ACA/IRS affordability (9.02% 2025 / 9.96% 2026); grandfathered flagged","edges":["E26"]},{"id":"T-C3","assert":"HSA employer contribution NOT counted as medical employer contribution","edges":["E6"]}]},{"stage":"Stage 3 — Output & Cross-cutting","cases":[{"id":"T-O1","assert":"Total remediation = A + B; healthcare pass/fail separate","edges":["E18"]},{"id":"T-O2","assert":"run_id threads the chain; methodology version snapshotted; audit complete","edges":[]},{"id":"T-O3","assert":"Owner-only share management; ADMIN sees all, ADVISOR own+shared","edges":[]}]}],"manualCases":[{"id":"M-1","case":"Login fail-closed","expected":"No users seeded → access denied, no default login"},{"id":"M-2","case":"Upload & preview","expected":"Verbatim preview shows every column, unchanged"},{"id":"M-3","case":"Flagged-row review","expected":"Flagged/rejected rows visible with a readable reason; none silently missing"},{"id":"M-4","case":"Correction flow","expected":"Correction persists, logged, re-derives; status review→final"},{"id":"M-5","case":"Verdict readability","expected":"Remediation (A+B) + per-plan healthcare pass/fail clear + correctly labeled"},{"id":"M-6","case":"Export","expected":"Structured output pastes cleanly into the acquisition model"},{"id":"M-7","case":"Degraded run banner","expected":"UI shows degraded clearly, not a silent full-confidence number"},{"id":"M-8","case":"ADVISOR run isolation","expected":"Cannot see another advisor’s unshared run"},{"id":"M-9","case":"ADMIN full visibility","expected":"ADMIN sees all runs"},{"id":"M-10","case":"Owner-only share mgmt","expected":"A non-owner cannot add/remove shares"},{"id":"M-11","case":"Invite / reset flows","expected":"Invite link + password reset work and expire correctly"}],"uat":{"note":"A deal-team member runs one or two REAL deal censuses end-to-end and confirms the output is usable in the acquisition model. Sign-off recorded.","exit":"Deal team accepts the verdict format + the remediation number’s presentation."},"e2eFlows":[{"id":"E2E-1","flow":"Happy path — login → upload clean census → run → verdict → export","covers":"U1–U7 · smoke"},{"id":"E2E-2","flow":"Flagged-review — upload edge census → review → correct → run","covers":"U3–U5"},{"id":"E2E-3","flow":"Auth/roles — ADVISOR cannot see another’s run; ADMIN can","covers":"U8 · authz"},{"id":"E2E-4","flow":"Sharing — owner shares → sharee sees it → non-owner can’t unshare","covers":"U8"},{"id":"E2E-5","flow":"Invite/reset — admin invites → accept-invite → login","covers":"U8"}],"nonFunctional":[{"type":"Performance","case":"200-employee census runs in acceptable time","priority":"P2"},{"type":"Security · authz","case":"ADVISOR cannot reach another’s run via the API directly","priority":"P1"},{"type":"Security · PII","case":"No PII/secret in logs or client responses","priority":"P1"},{"type":"Reproducibility","case":"Same census + methodology version → same number","priority":"P1"},{"type":"Accessibility","case":"Keyboard nav + labels on upload/review screens","priority":"P3"}],"testMeta":{"status":"DRAFT — pending team approval","source":"NineDean research/16-test-strategy.md","note":"E2E is design-only (no test code yet). Manual/UAT run on staging."}}'::jsonb),
  ('dataset_catalog', '{"datasetFiles":[{"name":"clean_baseline","rows":4,"purpose":"Happy path — every engine gives a sane number","outcome":"0 rejects, all engines fire"},{"name":"edge_ingestion","rows":9,"purpose":"E1–E8: coding, E/N exempt, blank-Code, dupes, HSA","outcome":"blank-Code → rejected not dropped"},{"name":"edge_geo","rows":3,"purpose":"E9–E12: unresolvable ZIP, cross-border, uncovered county","outcome":"fallbacks flagged; degraded=true"},{"name":"edge_fairpay_tax","rows":6,"purpose":"E13–E17: negative gross-up, tiers, waived, local tax","outcome":"floor never < basket; tax flags"},{"name":"edge_psl","rows":6,"purpose":"E18–E22: preempted, no-cap, capped, part-time, exempt","outcome":"correct floors per jurisdiction"},{"name":"edge_healthcare","rows":5,"purpose":"E23–E27: employer share, HDHP, non-compliant, waived","outcome":"verdicts affordable/review/fail"},{"name":"scale_large","rows":80,"purpose":"Volume / performance","outcome":"runs end-to-end"},{"name":"all_combined","rows":18,"purpose":"Regression smoke — one of each concern","outcome":"full-suite check"}],"edgeVariations":[{"group":"A · Ingestion / normalization","items":[{"id":"E1","variation":"Abbreviation-coded labels","expected":"Alias two-pass still maps them"},{"id":"E2","variation":"Exempt as E / N single letters","expected":"Parsed; exempt excluded from scope"},{"id":"E3","variation":"Blank Code row that still carries data","expected":"Flagged + rejected, never dropped"},{"id":"E4","variation":"Fully empty padding row","expected":"Skipped as padding"},{"id":"E5","variation":"Duplicate Code","expected":"Disambiguated, no silent merge"},{"id":"E6","variation":"HSA employer contribution column present","expected":"Not counted as medical employer contribution"},{"id":"E7","variation":"Missing dependent tier on a plan-holder","expected":"Defaults single + flag"},{"id":"E8","variation":"Unknown exempt status","expected":"Defaults in-scope + flag"}]},{"group":"B · Geo / county","items":[{"id":"E9","variation":"Unresolvable / missing residence ZIP","expected":"Home-office fallback, flagged"},{"id":"E10","variation":"Split-ZIP (spans counties)","expected":"Resolved via land-area share"},{"id":"E11","variation":"Cross-border commuter (residence ≠ work state)","expected":"County only if state-consistent, else flagged"},{"id":"E12","variation":"Uncovered county (no basket data)","expected":"Degraded basket, flagged"}]},{"group":"C · Fair Pay / tax","items":[{"id":"E13","variation":"Low-wage large family (credits drive tax negative)","expected":"Gross-up floored at 0; floor ≥ basket"},{"id":"E14","variation":"All four tiers EE / ES / EC / EF","expected":"filing_status from tier; dependents from enrollment"},{"id":"E15","variation":"Waived / unknown coverage","expected":"Methodology default household, flagged"},{"id":"E16","variation":"Enrollment vs tier mismatch","expected":"Falls back to tier base children, flagged"},{"id":"E17","variation":"Local-income-tax states (OH/PA/MI; MD/IN county)","expected":"Flagged where uncaptured"}]},{"group":"D · PSL","items":[{"id":"E18","variation":"Preempted state (TX/FL/GA/WI)","expected":"PSL floor 0"},{"id":"E19","variation":"No-cap accrual state (WA)","expected":"Floor 0"},{"id":"E20","variation":"Capped states (CA 40h, NY 56h, AZ/IL 40h)","expected":"Floor applied; gap costed"},{"id":"E21","variation":"Part-time (1040h)","expected":"Entitlement prorated to 2080h (→50%)"},{"id":"E22","variation":"Exempt employee","expected":"Out of PSL scope"}]},{"group":"E · Healthcare","items":[{"id":"E23","variation":"Low employer share (~50%)","expected":"Benchmark 1 fail → verdict review"},{"id":"E24","variation":"High employer share (~90–100%)","expected":"Verdict affordable"},{"id":"E25","variation":"HDHP plan choice","expected":"Do not fail Layer B on HDHP-as-preference"},{"id":"E26","variation":"Grandfathered / non-compliant plan","expected":"Flagged before benchmarks"},{"id":"E27","variation":"Waived enrollee (eligible, declined)","expected":"Not a false healthcare fail"}]}],"datasetMeta":{"status":"DRAFT — variations pending team confirmation","coverage":"Constrained to the 12 MIT-covered counties so expected outcomes are deterministic.","source":"NineDean research/15-edge-case-census-spec.md · backend/scripts/gen_test_datasets.py"}}'::jsonb)
